# Este script tem o objetivo de gerar e salvar um gráfico do fluxo de execução do sistema, ilustrando os possíveis loops.\n\nimport networkx as nx\nimport matplotlib.pyplot as plt\n\ndef_gerar_grafico():\n    # Cria o grafo direcionado\n    G = nx.DiGraph()\n    \n    # Define os nós do fluxo principal\n    nodes = [\"Start\", \"Check Project Size\", \"ReAct Agent\\n(Linear)\", \"Scanner\", \"Planner\", \"Reader\", \"Writer\", \"Critic\", \"End\"]\n    G.add_nodes_from(nodes)\n    \n    # Define as arestas para o fluxo de passos\n    edges = [\n        (\"Start\", \"Check Project Size\"),\n        (\"Check Project Size\", \"ReAct Agent\\n(Linear)\"),\n        (\"ReAct Agent\\n(Linear)\", \"End\"),\n        (\"Check Project Size\", \"Scanner\"),\n        (\"Scanner\", \"Planner\"),\n        (\"Planner\", \"Reader\"),\n        (\"Reader\", \"Writer\"),\n        (\"Writer\", \"Critic\"),\n        (\"Critic\", \"End\")\n    ]\n    G.add_edges_from(edges)\n    \n    # Adiciona a possível aresta de loop de refinamento\n    G.add_edge(\"Critic\", \"Writer\", label=\"Loop de Refinamento\\n(Se rejeitado)\")\n    \n    # Rótulos das arestas para as condições do tamanho do projeto e saídas\n    edge_labels = {\n        (\"Check Project Size\", \"ReAct Agent\\n(Linear)\"): \"<= 15 arquivos\",\n        (\"Check Project Size\", \"Scanner\"): \"> 15 arquivos\",\n        (\"Critic\", \"End\"): \"Aprovado\\nou Máx Iterações\",\n        (\"Critic\", \"Writer\"): \"Reprovado\"\n    }\n    \n    # Configurações de layout customizadas para melhor visualização\n    plt.figure(figsize=(14, 8))\n    pos = nx.spring_layout(G, k=0.8, iterations=50, seed=42)\n    \n    # Ajuste manual para alinhar melhor o fluxo de Critic até Writer\n    pos[\"Writer\"] = [0.2, 0.0]\n    pos[\"Critic\"] = [0.6, 0.0]\n    \n    # Desenha os nós com cor e transparência\n    nx.draw_networkx_nodes(G, pos, node_size=4000, node_color=\"skyblue\", alpha=0.9)\n    \n    # Adiciona os rótulos de texto aos nós\n    nx.draw_networkx_labels(G, pos, font_size=10, font_weight=\"bold\")\n    \n    # Desenha as arestas normais\n    nx.draw_networkx_edges(G, pos, edge_color=\"gray\", arrows=True, arrowstyle=\"-|>\", arrowsize=20, width=2)\n    \n    # Desenha a aresta de loop destacada em vermelho e curvada\n    nx.draw_networkx_edges(G, pos, edgelist=[(\"Critic\", \"Writer\")], edge_color=\"red\", \n                           connectionstyle='arc3, rad=0.2', arrows=True, arrowstyle=\"-|>\", arrowsize=20, width=2.5)\n    \n    # Desenha os rótulos das arestas\n    nx.draw_networkx_edge_labels(G, pos, edge_labels=edge_labels, font_color=\"darkred\", font_size=9)\n    \n    # Configura o título da imagem\n    plt.title(\"Gráfico de Fluxo de Execução com Possíveis Loops\", fontsize=15, fontweight=\"bold\")\n    plt.axis(\"off\")  # Oculta as bordas do gráfico\n    \n    # Salva a imagem\n    caminho_arquivo = \"fluxo_execucao_loops.png\"\n    plt.savefig(caminho_arquivo, format=\"png\", dpi=300, bbox_inches=\"tight\")\n    print(f\"Gráfico gerado com sucesso em '{caminho_arquivo}'\")\n\nif __name__ == \"__main__\":\n    def_gerar_grafico()\n
